// Normalizar resposta do Supabase REST
// REST retorna array JSON — n8n converte para items automaticamente
// Mas se a resposta vier como item unico com array, expandir manualmente

const items = $input.all();

// Caso 1: Veio como array dentro do primeiro item (comportamento ocasional do HTTP Request)
if (items.length === 1 && Array.isArray(items[0].json)) {
  const rows = items[0].json;
  if (rows.length === 0) {
    // Nenhum lead sem ad_id — finalizar
    return [{ json: { _empty: true, message: 'Nenhum lead sem ad_id encontrado. Backfill concluido.' } }];
  }
  return rows.map(row => ({ json: row }));
}

// Caso 2: Ja veio expandido (cada row = um item)
if (items.length > 0 && !items[0].json._empty) {
  return items;
}

// Sem dados
return [{ json: { _empty: true, message: 'Nenhum lead sem ad_id encontrado.' } }];

// Extrair attributionSource do contato retornado pelo GHL
// Referencia de campos (MEMORIA MOTTIVME):
//   adId, adsetId (NAO adSetId), campaignId, utmCampaign
//   utmSource, medium (NAO utmMedium), utmContent, sessionSource

const items = $input.all();
const results = [];

for (const item of items) {
  // GHL retorna { contact: { id, attributionSource, ... } }
  const contact = item.json?.contact || item.json || {};
  const contactId = contact?.id || null;
  const attribution = contact?.attributionSource || {};

  // Verificar se a resposta e valida (status 200 com contact)
  if (!contactId) {
    // Contato nao encontrado ou erro na API — pular
    console.log('Contact nao encontrado ou resposta invalida:', JSON.stringify(item.json).substring(0, 200));
    continue;
  }

  const adId = attribution.adId || null;
  const adsetId = attribution.adsetId || null;          // CORRETO: adsetId (nao adSetId)
  const campaignId = attribution.campaignId || null;
  const utmCampaign = attribution.utmCampaign || null;
  const utmSource = attribution.utmSource || null;
  const utmMedium = attribution.medium || null;         // CORRETO: medium (nao utmMedium)
  const utmContent = attribution.utmContent || null;
  const sessionSource = attribution.sessionSource || null;

  results.push({
    json: {
      contactId,
      adId,
      adsetId,
      campaignId,
      utmCampaign,
      utmSource,
      utmMedium,
      utmContent,
      sessionSource,
      hasAttribution: !!(adId),
      // Guardar raw para debug
      _rawAttribution: Object.keys(attribution).length > 0 ? attribution : null
    }
  });
}

// Se nenhum resultado valido, retornar item vazio para nao quebrar o workflow
if (results.length === 0) {
  return [{ json: { _noValidContacts: true } }];
}

return results;

