// Aguarda 2 segundos entre batches para respeitar rate limit do GHL
// GHL Agency PIT tem limite maior (~600 req/min), mas 2s por batch de 10 = seguro
await new Promise(resolve => setTimeout(resolve, 2000));
return $input.all();

// Sumarizar resultados do backfill
const allItems = $input.all();

// Contar registros que foram efetivamente atualizados (tem unique_id ou id na resposta do PATCH)
const updatedCount = allItems.filter(item => {
  const j = item.json;
  return Array.isArray(j) ? j.length > 0 : (j?.unique_id || j?.id);
}).length;

const now = new Date().toISOString();

console.log(`[Backfill Ad Attribution] ${now} | Atualizados: ${updatedCount} registros`);

return [{
  json: {
    executedAt: now,
    totalUpdated: updatedCount,
    message: `Backfill concluido: ${updatedCount} leads tiveram ad_id e campos de atribuicao preenchidos.`
  }
}];
